function isPrime(num) {
    // Check if the number is less than or equal to 1
    if (num <= 1) {
        return false;
    }
    // Loop from 2 to the square root of the number
    // (excluding the square root itself)
    for (let i = 2; i <= Math.sqrt(num); i++) {
        // If the number is divisible by any of these, it's not prime
        if (num % i === 0) {
            return false;
        }
    }
    // If no divisors were found, the number is prime
    return true;
}

function findAndPrintPrimeNumbers(numbers) {
    // Ensure the array has exactly 5 numbers
    if (numbers.length !== 5) {
        console.error("Expected an array of exactly 5 numbers.");
        return;
    }

    // Loop through the array to check each number
